DELETE FROM seller_products sp USING _kd WHERE sp.asin = _kd.asin AND sp.marketplace = 'flipkart';
DELETE FROM brand_checking bc USING _kd WHERE bc.asin = _kd.asin AND bc.marketplace = 'flipkart';
DELETE FROM flipkart_master_sellers m USING _kd WHERE m.asin = _kd.asin;

DELETE FROM seller_products sp USING _kd WHERE sp.asin = _kd.asin AND sp.marketplace = 'india';
DELETE FROM brand_checking bc USING _kd WHERE bc.asin = _kd.asin AND bc.marketplace = 'india';
DELETE FROM india_master_sellers m USING _kd WHERE m.asin = _kd.asin;

SELECT unified_recalc_progress('flipkart', s) FROM generate_series(1,6) s;
SELECT unified_recalc_progress('india', s) FROM generate_series(1,8) s;

DROP TABLE _kd;
